+    return {
+      transport: "chrome",
+      found: false,
+      tab,
+      message: params.url
+        ? `No existing Meet tab matched ${params.url}.`
+        : "No existing Meet tab found in local Chrome.",
+    };
+  }
+  return {
+    transport: "chrome",
+    ...(await inspectRecoverableMeetTab({
+      callBrowser: callLocalBrowserRequest,
+      config: params.config,
+      timeoutMs,
+      tab,
+      targetId,
+    })),
